#include <stdio.h>
int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    const char *alpha="abcdefghijklmnopqrstuvwxyz";
    for(int tc=0; tc<T; ++tc){
        char start; int rot;
        scanf(" %c",&start);
        scanf("%d",&rot); // ignored
        int idx=start-'a';
        for(int i=0;i<26;++i) putchar(alpha[(idx+i)%26]);
        if(tc<T-1) putchar('\n');
    }
    return 0;
}

