        char start; int rot; cin>>start>>rot; // rot ignored
        int idx=start-'a';
        for(int i=0;i<26;++i) cout<<alpha[(idx+i)%26];
        if(T) cout<<'\n';
    }
    return 0;
}

code.Java:
import java.io.*;
public class Main{
    public static void main(String[] args) throws Exception{
        BufferedReader br=new BufferedReader(new InputStreamReader(System.in));
        int T=Integer.parseInt(br.readLine().trim());
        String alpha="abcdefghijklmnopqrstuvwxyz";
        StringBuilder sb=new StringBuilder();
        for(int tc=0; tc<T; ++tc){
            char start=br.readLine().trim().charAt(0);
            br.readLine(); // rotations ignored
            int idx=start-'a';
            for(int i=0;i<26;++i) sb.append(alpha.charAt((idx+i)%26));
            if(tc<T-1) sb.append('\n');
        }
        System.out.print(sb.toString());
    }
}

