const fs=require('fs');
const input=fs.readFileSync(0,'utf-8').trim().split('\n');
let idx=0;
const T=parseInt(input[idx++],10);
const alpha='abcdefghijklmnopqrstuvwxyz';
let results=[];
for(let tc=0; tc<T; ++tc){
  const start=input[idx++].trim();
  idx++; // skip rotations line
  const startIdx=start.charCodeAt(0)-97;
  let s='';
  for(let i=0;i<26;++i) s+=alpha[(startIdx+i)%26];
  results.push(s);
}
console.log(results.join('\n'));

